class ModelIntegrityChecker:
    def __init__(self, trusted_hashes_file: str = "trusted_model_hashes.json"):
        self.trusted_hashes_file = trusted_hashes_file
        self.trusted_hashes = self._load_trusted_hashes()
    
    def _load_trusted_hashes(self) -> Dict:
        if os.path.exists(self.trusted_hashes_file):
            with open(self.trusted_hashes_file, 'r') as f:
                return json.load(f)
        return {}
    
    def _save_trusted_hashes(self):
        with open(self.trusted_hashes_file, 'w') as f:
            json.dump(self.trusted_hashes, f, indent=2)
    
    def compute_file_hash(self, filepath: str) -> str:
        sha256_hash = hashlib.sha256()
        with open(filepath, "rb") as f:
            for byte_block in iter(lambda: f.read(4096), b""):
                sha256_hash.update(byte_block)
        return sha256_hash.hexdigest()
    
    def verify_model_hash(self, filepath: str, model_name: str) -> bool:
        computed_hash = self.compute_file_hash(filepath)
        if model_name in self.trusted_hashes:
            return computed_hash == self.trusted_hashes[model_name]
        return False
    
    def add_trusted_model(self, filepath: str, model_name: str):
        computed_hash = self.compute_file_hash(filepath)
        self.trusted_hashes[model_name] = computed_hash
        self._save_trusted_hashes()
    
    def scan_model_weights(self, state_dict: OrderedDict) -> Dict:
        anomalies = {
            'suspicious_layers': [],
            'unusual_statistics': [],
            'extreme_values': []
        }
        
        for name, param in state_dict.items():
            if isinstance(param, torch.Tensor):
                param_np = param.cpu().numpy()
                
                mean_val = np.mean(param_np)
                std_val = np.std(param_np)
                max_val = np.max(np.abs(param_np))
                
                if max_val > 1e6:
                    anomalies['extreme_values'].append({
                        'layer': name,
                        'max_value': float(max_val)
                    })
                
                if std_val > 100:
                    anomalies['unusual_statistics'].append({
                        'layer': name,
                        'std': float(std_val),
                        'mean': float(mean_val)
                    })
                
                if 'backdoor' in name.lower() or 'trigger' in name.lower():
                    anomalies['suspicious_layers'].append(name)
        
        return anomalies


class SecureModelDownloader:
    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = cache_dir
        os.makedirs(cache_dir, exist_ok=True)
        self.integrity_checker = ModelIntegrityChecker()
    
    def download_model(self, url: str, model_name: str, verify_ssl: bool = True) -> str:
        filepath = os.path.join(self.cache_dir, f"{model_name}.pth")
        
        if os.path.exists(filepath):
            if self.integrity_checker.verify_model_hash(filepath, model_name):
                print(f"Model {model_name} already exists and verified.")
                return filepath
            else:
                warnings.warn(f"Cached model {model_name} failed integrity check. Re-downloading.")
        
        print(f"Downloading model from {url}...")
        response = requests.get(url, verify=verify_ssl, stream=True)
        response.raise_for_status()
        
        with open(filepath, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                f.write(chunk)
        
        print(f"Model downloaded to {filepath}")
        return filepath
    
    def load_model_safely(self, filepath: str, model_name: str, 
                         verify_integrity: bool = True,
                         scan_for_anomalies: bool = True) -> OrderedDict:
        if verify_integrity and model_name in self.integrity_checker.trusted_hashes:
            if not self.integrity_checker.verify_model_hash(filepath, model_name):
                raise ValueError(f"Model integrity check failed for {model_name}")
        
        state_dict = torch.load(filepath, map_location='cpu', weights_only=True)
        
        if scan_for_anomalies:
            anomalies = self.integrity_checker.scan_model_weights(state_dict)
            if any(anomalies.values()):
                warnings.warn(f"Anomalies detected in model: {anomalies}")
        
        return state_dict


class BackdoorDefenseLayer(nn.Module):
    def __init__(self, input_dim: int, defense_type: str = 'activation_clustering'):
        super(BackdoorDefenseLayer, self).__init__()
        self.defense_type = defense_type
        self.input_dim = input_dim
        self.activation_threshold = nn.Parameter(torch.tensor(0.0), requires_grad=False)
        
    def forward(self, x):
        if self.defense_type == 'activation_clustering':
            x = torch.clamp(x, -10, 10)
        return x


class SecureTransferLearningModel(nn.Module):
    def __init__(self, base_model: nn.Module, num_classes: int, 
                 freeze_base: bool = True, add_defense: bool = True):
        super(SecureTransferLearningModel, self).__init__()
        self.base_model = base_model
        self.add_defense = add_defense
        
        if freeze_base:
            for param in self.base_model.parameters():
                param.requires_grad = False
        
        if hasattr(base_model, 'fc'):
            in_features = base_model.fc.in_features
            self.base_model.fc = nn.Identity()
        elif hasattr(base_model, 'classifier'):
            if isinstance(base_model.classifier, nn.Sequential):
                in_features = base_model.classifier[-1].in_features
            else:
                in_features = base_model.classifier.in_features
            self.base_model.classifier = nn.Identity()
        else:
            in_features = 512
        
        layers = []
        if add_defense:
            layers.append(BackdoorDefenseLayer(in_features))
        
        layers.extend([
            nn.Linear(in_features, 256),
            nn.ReLU(),
            nn.Dropout(0.5),
            nn.Linear(256, num_classes)
        ])
        
        self.classifier = nn.Sequential(*layers)
    
    def forward(self, x):
        features = self.base_model(x)
        return self.classifier(features)


class CustomDataset(Dataset):
    def __init__(self, data: List, labels: List, transform=None):
        self.data = data
        self.labels = labels
        self.transform = transform
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        sample = self.data[idx]
        label = self.labels[idx]
        
        if self.transform:
            sample = self.transform(sample)
        
        return sample, label


class TransferLearningPipeline:
    def __init__(self, model_cache_dir: str = "./model_cache"):
        self.downloader = SecureModelDownloader(cache_dir=model_cache_dir)
        self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    
    def download_and_verify_model(self, url: str, model_name: str, 
                                  expected_hash: Optional[str] = None) -> str:
        filepath = self.downloader.download_model(url, model_name)
        
        if expected_hash:
            self.downloader.integrity_checker.trusted_hashes[model_name] = expected_hash
            self.downloader.integrity_checker._save_trusted_hashes()
        
        return filepath
    
    def load_pretrained_model(self, model_type: str = 'resnet18', 
                             custom_weights_path: Optional[str] = None,
                             model_name: Optional[str] = None) -> nn.Module:
        if custom_weights_path and model_name:
            state_dict = self.downloader.load_model_safely(
                custom_weights_path, 
                model_name,
                verify_integrity=True,
                scan_for_anomalies=True
            )
            
            if model_type == 'resnet18':
                model = models.resnet18(weights=None)
            elif model_type == 'resnet50':
                model = models.resnet50(weights=None)
            elif model_type == 'vgg16':
                model = models.vgg16(weights=None)
            else:
                raise ValueError(f"Unsupported model type: {model_type}")
            
            model.load_state_dict(state_dict, strict=False)
        else:
            if model_type == 'resnet18':
                model = models.resnet18(weights=models.ResNet18_Weights.IMAGENET1K_V1)
            elif model_type == 'resnet50':
                model = models.resnet50(weights=models.ResNet50_Weights.IMAGENET1K_V1)
            elif model_type == 'vgg16':
                model = models.vgg16(weights=models.VGG16_Weights.IMAGENET1K_V1)
            else:
                raise ValueError(f"Unsupported model type: {model_type}")
        
        return model
    
    def fine_tune_model(self, model: nn.Module, train_loader: DataLoader, 
                       val_loader: DataLoader, num_epochs: int = 10,
                       learning_rate: float = 0.001) -> nn.Module:
        model = model.to(self.device)
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(filter(lambda p: p.requires_grad, model.parameters()), 
                              lr=learning_rate)
        scheduler = optim.lr_scheduler.StepLR(optimizer, step_size=5, gamma=0.1)
        
        best_val_acc = 0.0
        
        for epoch in range(num_epochs):
            model.train()
            train_loss = 0.0
            train_correct = 0
            train_total = 0
            
            for inputs, labels in train_loader:
                inputs, labels = inputs.to(self.device), labels.to(self.device)
                
                optimizer.zero_grad()
                outputs = model(inputs)
                loss = criterion(outputs, labels)
                loss.backward()
                
                torch.nn.utils.clip_grad_norm_(model.parameters(), max_norm=1.0)
                
                optimizer.step()
                
                train_loss += loss.item()
                _, predicted = outputs.max(1)
                train_total += labels.size(0)
                train_correct += predicted.eq(labels).sum().item()
            
            train_acc = 100. * train_correct / train_total
            
            model.eval()
            val_loss = 0.0
            val_correct = 0
            val_total = 0
            
            with torch.no_grad():
                for inputs, labels in val_loader:
                    inputs, labels = inputs.to(self.device), labels.to(self.device)
                    outputs = model(inputs)
                    loss = criterion(outputs, labels)
                    
                    val_loss += loss.item()
                    _, predicted = outputs.max(1)
                    val_total += labels.size(0)
                    val_correct += predicted.eq(labels).sum().item()
            
            val_acc = 100. * val_correct / val_total
            
            print(f"Epoch {epoch+1}/{num_epochs}")
            print(f"Train Loss: {train_loss/len(train_loader):.4f}, Train Acc: {train_acc:.2f}%")
            print(f"Val Loss: {val_loss/len(val_loader):.4f}, Val Acc: {val_acc:.2f}%")
            
            if val_acc > best_val_acc:
                best_val_acc = val_acc
                torch.save(model.state_dict(), 'best_model.pth')
            
            scheduler.step()
        
        return model
    
    def detect_backdoor_triggers(self, model: nn.Module, test_loader: DataLoader,
                                num_samples: int = 100) -> Dict:
        model.eval()
        activations = []
        predictions = []
        
        with torch.no_grad():
            for i, (inputs, labels) in enumerate(test_loader):
                if i >= num_samples:
                    break
                
                inputs = inputs.to(self.device)
                outputs = model(inputs)
                _, predicted = outputs.max(1)
                
                activations.append(outputs.cpu().numpy())
                predictions.append(predicted.cpu().numpy())
        
        activations = np.concatenate(activations, axis=0)
        predictions = np.concatenate(predictions, axis=0)
        
        activation_mean = np.mean(activations, axis=0)
        activation_std = np.std(activations, axis=0)
        
        suspicious_indices = np.where(activation_std > 3 * np.mean(activation_std))[0]
        
        return {
            'suspicious_neurons': suspicious_indices.tolist(),
            'activation_statistics': {
                'mean': activation_mean.tolist(),
                'std': activation_std.tolist()
            }
        }


def create_sample_dataset(num_samples: int = 100, num_classes: int = 10):
    data = [torch.randn(3, 224, 224) for _ in range(num_samples)]
    labels = [np.random.randint(0, num_classes) for _ in range(num_samples)]
    return data, labels


